window.YSOAM_LUCIDE.icon = function (name, size) {
  var paths = window.YSOAM_LUCIDE[name];
  return paths ? window.YSOAM_LUCIDE.svg(paths, size) : '';
};

window.YSOAM_LUCIDE.init = function (root) {
  if (!window.YSOAM_LUCIDE) return;
  (root || document).querySelectorAll('[data-lucide-icon], [data-wo-icon]').forEach(function (el) {
    var name = el.getAttribute('data-lucide-icon') || el.getAttribute('data-wo-icon');
    var size = parseInt(el.getAttribute('data-lucide-icon-size') || el.getAttribute('data-wo-icon-size'), 10) || 16;
    if (name) el.innerHTML = window.YSOAM_LUCIDE.icon(name, size);
  });
};
